package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private MockedStatic<Files> filesMockedStatic;

    @BeforeEach
    void setUp() {
        filesMockedStatic = Mockito.mockStatic(Files.class);
    }

    @AfterEach
    void tearDown() {
        filesMockedStatic.close();
    }

    @Test
    void parse_givenNullPath_throwsException() {
        Path path = null;
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);

        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(path, charset, format);
        });
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_givenNullFormat_throwsException() {
        Path path = mock(Path.class);
        Charset charset = Charset.defaultCharset();
        CSVFormat format = null;

        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(path, charset, format);
        });
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_readsBufferedReaderAndDelegates() throws IOException {
        Path path = mock(Path.class);
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);
        BufferedReader reader = mock(BufferedReader.class);

        filesMockedStatic.when(() -> Files.newBufferedReader(path, charset)).thenReturn(reader);

        // Use reflection to invoke private static parse(Reader, CSVFormat)
        CSVParser dummyParser = mock(CSVParser.class);

        try (MockedStatic<CSVParser> csvParserStatic = Mockito.mockStatic(CSVParser.class)) {
            csvParserStatic.when(() -> CSVParser.parse(reader, format)).thenReturn(dummyParser);

            CSVParser result = CSVParser.parse(path, charset, format);

            assertSame(dummyParser, result);

            filesMockedStatic.verify(() -> Files.newBufferedReader(path, charset));
            csvParserStatic.verify(() -> CSVParser.parse(reader, format));
        }
    }
}
